import {Dimensions, Platform} from 'react-native';
const {width: SCREEN_WIDTH} = Dimensions.get('window');
export const SPACING = {xs:4,sm:8,md:16,lg:24,xl:32} as const;
export const RADII = {card:20} as const;
export const CARD = {width: SCREEN_WIDTH - SPACING.lg*2, height: SCREEN_WIDTH*1.3} as const;
export const COLORS = {bg:'#0B0B0F', card:'#16161D', text:'#F2F2F7', muted:'#8E8E93'} as const;

// CardStack.tsx
import React, {useCallback, useState} from 'react';
import {StyleSheet, View, Text, Platform} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, withDecay, runOnJS, interpolate, Extrapolation, useDerivedValue} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
import {SPACING, RADII, CARD, COLORS} from './theme';

type Card = {id: string; title: string; subtitle: string};
type Props = {cards: Card[]; onDismiss: (id: string, dir: 'left'|'right') => void};

const SWIPE_THRESHOLD = CARD.width * 0.3;
const VELOCITY_THRESHOLD = 800;

export function CardStack({cards, onDismiss}: Props) {
  const [index, setIndex] = useState(0);
  const x = useSharedValue(0); const y = useSharedValue(0);
  const advance = useCallback((id: string, dir: 'left'|'right') => { Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium); onDismiss(id, dir); setIndex(i => i+1); x.value = 0; y.value = 0; }, [onDismiss, x, y]);
  const top = cards[index]; const next = cards[index+1];
  const pan = Gesture.Pan().activeOffsetX([-10,10]).failOffsetY([-20,20]).onUpdate(e => { x.value = e.translationX; y.value = e.translationY * 0.4; }).onEnd(e => { const past = Math.abs(e.translationX) > SWIPE_THRESHOLD || Math.abs(e.velocityX) > VELOCITY_THRESHOLD; if (past && top) { const dir = e.translationX > 0 ? 'right':'left'; x.value = withDecay({velocity: e.velocityX, deceleration: 0.997}, () => runOnJS(advance)(top.id, dir)); } else { x.value = withSpring(0, {damping: 15, stiffness: 180}); y.value = withSpring(0, {damping: 15, stiffness: 180}); } });
  const rotate = useDerivedValue(() => interpolate(x.value, [-CARD.width, 0, CARD.width], [-15, 0, 15], Extrapolation.CLAMP));
  const topStyle = useAnimatedStyle(() => ({transform: [{translateX: x.value}, {translateY: y.value}, {translateY: CARD.height/2}, {rotate: `${rotate.value}deg`}, {translateY: -CARD.height/2}]}));
  const nextStyle = useAnimatedStyle(() => ({transform: [{scale: interpolate(Math.abs(x.value), [0, SWIPE_THRESHOLD], [0.94, 1], Extrapolation.CLAMP)}]}));
  return (<View style={s.root}>{next && (<Animated.View style={[s.card, nextStyle]}><Text style={s.title}>{next.title}</Text></Animated.View>)}{top && (<GestureDetector gesture={pan}><Animated.View style={[s.card, topStyle]}><Text style={s.title}>{top.title}</Text><Text style={s.sub}>{top.subtitle}</Text></Animated.View></GestureDetector>)}</View>);
}
const s = StyleSheet.create({root:{flex:1, alignItems:'center', justifyContent:'center', backgroundColor:COLORS.bg}, card:{position:'absolute', width:CARD.width, height:CARD.height, backgroundColor:COLORS.card, borderRadius:RADII.card, padding:SPACING.lg, ...Platform.select({ios:{shadowColor:'#000', shadowOpacity:0.3, shadowRadius:24, shadowOffset:{width:0,height:12}}, android:{elevation:12}})}, title:{color:COLORS.text, fontSize:28, fontWeight:'700'}, sub:{color:COLORS.muted, fontSize:16, marginTop:SPACING.sm}});

// BottomSheet.tsx
import React, {forwardRef, useImperativeHandle} from 'react';
import {Dimensions, Keyboard, Platform, Pressable, StyleSheet, Text, View} from 'react-native';
import {Gesture, GestureDetector, ScrollView as GHScrollView} from 'react-native-gesture-handler';
import Animated, {Extrapolation, interpolate, runOnJS, useAnimatedKeyboard, useAnimatedReaction, useAnimatedScrollHandler, useAnimatedStyle, useSharedValue, withSpring} from 'react-native-reanimated';
import {useSafeAreaInsets} from 'react-native-safe-area-context';

const H = Dimensions.get('window').height;
const SNAP_RATIOS = [0.25, 0.6, 0.92] as const;
const snapY = SNAP_RATIOS.map((ratio) => H * (1 - ratio));
export type BottomSheetRef = { snapTo: (index: number) => void; close: () => void };

export const BottomSheet = forwardRef<BottomSheetRef, {onClose: () => void; children: React.ReactNode}>(({onClose, children}, ref) => {
  const insets = useSafeAreaInsets();
  const keyboard = useAnimatedKeyboard();
  const y = useSharedValue(snapY[1]);
  const startY = useSharedValue(snapY[1]);
  const snapIndex = useSharedValue(1);
  const scrollY = useSharedValue(0);

  const commitSnap = (next: number) => {
    'worklet';
    snapIndex.value = next;
    y.value = withSpring(snapY[next], {damping: 22, stiffness: 230});
  };
  useImperativeHandle(ref, () => ({snapTo: (index) => { snapIndex.value = index; y.value = withSpring(snapY[index]); }, close: () => { y.value = withSpring(H, {}, () => runOnJS(onClose)()); }}), [onClose]);
  useAnimatedReaction(() => keyboard.height.value, (height) => { if (height > 0) commitSnap(2); });

  const headerPan = Gesture.Pan().onBegin(() => { startY.value = y.value; }).onUpdate((event) => { y.value = Math.max(snapY[2], startY.value + event.translationY); }).onEnd((event) => {
    const projected = y.value + event.velocityY * 0.16;
    if (projected > snapY[0] + 96) { y.value = withSpring(H, {}, () => runOnJS(onClose)()); return; }
    const next = snapY.reduce((best, value, index) => Math.abs(projected - value) < Math.abs(projected - snapY[best]) ? index : best, snapIndex.value);
    commitSnap(next);
  });
  const bodyPan = Gesture.Pan().onBegin(() => { startY.value = y.value; }).onUpdate((event) => { if (snapIndex.value < 2 || (scrollY.value <= 0 && event.translationY > 0)) y.value = Math.max(snapY[2], startY.value + event.translationY); }).onEnd((event) => { if (snapIndex.value < 2 || event.translationY > 20) headerPan; });
  const scrollHandler = useAnimatedScrollHandler((event) => { scrollY.value = event.contentOffset.y; });
  const sheetStyle = useAnimatedStyle(() => ({transform: [{translateY: y.value - keyboard.height.value}], paddingBottom: insets.bottom + Math.max(12, keyboard.height.value ? 8 : 16)}));
  const backdropStyle = useAnimatedStyle(() => ({opacity: interpolate(y.value, [snapY[0], snapY[2]], [0.1, 0.52], Extrapolation.CLAMP)}));

  return <View pointerEvents="box-none" style={StyleSheet.absoluteFill}><Animated.View style={[styles.backdrop, backdropStyle]} /><GestureDetector gesture={headerPan}><Animated.View style={[styles.sheet, sheetStyle]} accessibilityViewIsModal accessibilityLabel="Send money sheet"><View style={styles.handle} accessibilityRole="adjustable" accessibilityActions={[{name:'increment'}, {name:'decrement'}]} /><Text style={styles.title}>Send money</Text><GestureDetector gesture={bodyPan}><Animated.View style={styles.body}><GHScrollView onScroll={scrollHandler} scrollEventThrottle={16} keyboardShouldPersistTaps="handled">{children}</GHScrollView></Animated.View></GestureDetector><Pressable accessibilityRole="button" accessibilityLabel="Close sheet" onPress={onClose} style={styles.close}><Text>Close</Text></Pressable></Animated.View></GestureDetector></View>;
});
const styles = StyleSheet.create({backdrop: {...StyleSheet.absoluteFillObject, backgroundColor: 'black'}, sheet: {position: 'absolute', left: 0, right: 0, height: H, borderTopLeftRadius: 24, borderTopRightRadius: 24, backgroundColor: 'white', padding: 18, gap: 12, ...Platform.select({ios: {shadowOpacity: 0.2, shadowRadius: 18}, android: {elevation: 24}})}, handle: {alignSelf: 'center', width: 40, height: 5, borderRadius: 3, backgroundColor: '#cbd5e1'}, title: {fontSize: 20, fontWeight: '700'}, body: {flex: 1}, close: {minHeight: 44, justifyContent: 'center'}});

