import React, {memo, useEffect, useSyncExternalStore} from 'react';
import {StyleSheet, View, Text, Pressable} from 'react-native';
import {Image} from 'expo-image';
import Animated, {useSharedValue, useAnimatedStyle, withTiming, withSpring} from 'react-native-reanimated';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import * as Haptics from 'expo-haptics';
import {useLikesStore} from './LikesStore';

export type FeedItem = {id: string; user: string; avatar: string; image: string; aspectRatio: number; caption: string};
export const ROW_ESTIMATE = 480;

export const FeedRow = memo(function FeedRow({item, width}: {item: FeedItem; width: number}) {
  const liked = useLikesStore(item.id);
  const toggle = useLikesStore.toggle;
  const opacity = useSharedValue(0);
  const heartScale = useSharedValue(0);
  useEffect(() => { opacity.value = 0; }, [item.id]);
  const onLoad = () => { opacity.value = withTiming(1, {duration: 220}); };
  const doubleTap = Gesture.Tap().numberOfTaps(2).onEnd(() => { 'worklet'; heartScale.value = withSpring(1, {damping:10, stiffness:200}, () => { heartScale.value = withTiming(0, {duration: 400}); }); }).runOnJS(false);
  const onDoubleLike = () => { Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light); if (!liked) toggle(item.id); };
  doubleTap.onEnd(() => { 'worklet'; }).runOnJS(true);
  const imgStyle = useAnimatedStyle(() => ({opacity: opacity.value}));
  const heartStyle = useAnimatedStyle(() => ({transform: [{scale: heartScale.value}], opacity: heartScale.value}));
  const imgH = width / item.aspectRatio;
  return (<View style={s.row}><View style={s.header}><Image source={item.avatar} style={s.avatar} contentFit='cover'/><Text style={s.user}>{item.user}</Text></View><GestureDetector gesture={doubleTap}><View style={[s.imageWrap, {height: imgH}]}><Animated.View style={[StyleSheet.absoluteFill, imgStyle]}><Image source={item.image} style={StyleSheet.absoluteFill} contentFit='cover' onLoad={onLoad} cachePolicy='memory-disk' recyclingKey={item.id}/></Animated.View><Animated.View style={[s.heart, heartStyle]} pointerEvents='none'><Text style={s.heartGlyph}>{'♥'}</Text></Animated.View></View></GestureDetector><View style={s.actions}><Pressable hitSlop={10} onPress={() => { Haptics.selectionAsync(); toggle(item.id); }}><Text style={[s.actionGlyph, liked && s.likedGlyph]}>{liked ? '♥' : '♡'}</Text></Pressable></View><Text style={s.caption} numberOfLines={2}><Text style={s.user}>{item.user} </Text>{item.caption}</Text></View>);
}, (a, b) => a.item.id === b.item.id && a.width === b.width);

const s = StyleSheet.create({row:{paddingBottom:12, backgroundColor:'#000'}, header:{flexDirection:'row', alignItems:'center', padding:12, gap:10}, avatar:{width:32, height:32, borderRadius:16, backgroundColor:'#1C1C1E'}, user:{color:'#fff', fontWeight:'600'}, imageWrap:{width:'100%', backgroundColor:'#0A0A0A', justifyContent:'center', alignItems:'center'}, actions:{flexDirection:'row', padding:12, gap:16}, actionGlyph:{fontSize:26, color:'#fff'}, likedGlyph:{color:'#FF3B5C'}, caption:{paddingHorizontal:12, color:'#E5E5EA', fontSize:14, lineHeight:18}, heart:{position:'absolute'}, heartGlyph:{fontSize:96, color:'#fff', textShadowColor:'rgba(0,0,0,0.5)', textShadowRadius:8}});

// LikesStore.ts (useSyncExternalStore per id)
import {useSyncExternalStore} from 'react';
const likes = new Map<string, boolean>();
const listeners = new Map<string, Set<() => void>>();
function subscribe(id: string, cb: () => void) { let set = listeners.get(id); if (!set) { set = new Set(); listeners.set(id, set); } set.add(cb); return () => set!.delete(cb); }
function emit(id: string) { listeners.get(id)?.forEach(cb => cb()); }
function get(id: string) { return likes.get(id) ?? false; }
function toggle(id: string) { likes.set(id, !get(id)); emit(id); }
export const useLikesStore = Object.assign((id: string) => useSyncExternalStore(cb => subscribe(id, cb), () => get(id)), {toggle});

