// OtpInput.tsx
import React, {useCallback, useImperativeHandle, useRef, useState, forwardRef} from 'react';
import {StyleSheet, View, TextInput, Pressable, Platform, NativeSyntheticEvent, TextInputKeyPressEventData} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withSequence, withTiming, runOnJS} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';

const LENGTH = 6;
export type OtpInputRef = {clear: () => void; shake: () => void; focus: () => void};
type Props = {onComplete: (code: string) => void; autoFocus?: boolean};

export const OtpInput = forwardRef<OtpInputRef, Props>(({onComplete, autoFocus = true}, ref) => {
  const [value, setValue] = useState('');
  const inputRef = useRef<TextInput>(null);
  const shakeX = useSharedValue(0);
  const shake = useCallback(() => { Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error); shakeX.value = withSequence(withTiming(-8, {duration:50}), withTiming(8, {duration:50}), withTiming(-6, {duration:50}), withTiming(6, {duration:50}), withTiming(0, {duration:50})); }, [shakeX]);
  useImperativeHandle(ref, () => ({clear: () => setValue(''), shake, focus: () => inputRef.current?.focus()}));
  const onChangeText = (next: string) => { const clean = next.replace(/\D/g, '').slice(0, LENGTH); setValue(clean); if (clean.length === LENGTH) { Haptics.selectionAsync(); onComplete(clean); } };
  const onKeyPress = (e: NativeSyntheticEvent<TextInputKeyPressEventData>) => { if (e.nativeEvent.key === 'Backspace' && value.length > 0) { Haptics.selectionAsync(); } };
  const shakeStyle = useAnimatedStyle(() => ({transform: [{translateX: shakeX.value}]}));
  const cells = Array.from({length: LENGTH});
  return (<Animated.View style={[s.row, shakeStyle]}><TextInput ref={inputRef} value={value} onChangeText={onChangeText} onKeyPress={onKeyPress} keyboardType='number-pad' maxLength={LENGTH} autoFocus={autoFocus} textContentType={Platform.OS === 'ios' ? 'oneTimeCode' : undefined} autoComplete={Platform.OS === 'android' ? 'sms-otp' : 'one-time-code'} style={s.hidden} caretHidden/>{cells.map((_, i) => { const filled = i < value.length; const active = i === value.length; return (<Pressable key={i} onPress={() => inputRef.current?.focus()} style={[s.cell, active && s.cellActive, filled && s.cellFilled]}>{filled ? <Animated.Text style={s.digit}>{value[i]}</Animated.Text> : active ? <View style={s.caret}/> : null}</Pressable>); })}</Animated.View>);
});
const s = StyleSheet.create({row:{flexDirection:'row', justifyContent:'center', gap:8}, hidden:{position:'absolute', width:1, height:1, opacity:0}, cell:{width:48, height:60, borderRadius:12, borderWidth:1, borderColor:'#2C2C2E', backgroundColor:'#1C1C1E', alignItems:'center', justifyContent:'center'}, cellActive:{borderColor:'#0A84FF', borderWidth:2}, cellFilled:{borderColor:'#3A3A3C'}, digit:{color:'#fff', fontSize:28, fontVariant:['tabular-nums'], fontWeight:'600'}, caret:{width:2, height:28, backgroundColor:'#0A84FF', borderRadius:1}});

