// SharedImage.tsx
import React, {createContext, useContext, useState, useCallback, useRef} from 'react';
import {StyleSheet, View, Dimensions} from 'react-native';
import {Image} from 'expo-image';
import Animated, {useSharedValue, useAnimatedStyle, withTiming, Easing, runOnJS} from 'react-native-reanimated';
import {useSafeAreaInsets} from 'react-native-safe-area-context';

const {width: SW, height: SH} = Dimensions.get('window');
type Frame = {x:number; y:number; w:number; h:number};
type Active = {id:string; uri:string; source:Frame; target:Frame; aspectRatio:number};
type Ctx = {open: (a: Active) => void; close: () => void; progress: Animated.SharedValue<number>; active: Active | null};
const C = createContext<Ctx | null>(null);
export const useSharedImage = () => { const c = useContext(C); if (!c) throw new Error('SharedImageProvider missing'); return c; };

export function SharedImageProvider({children}: {children: React.ReactNode}) {
  const [active, setActive] = useState<Active | null>(null);
  const progress = useSharedValue(0);
  const open = useCallback((a: Active) => { setActive(a); progress.value = 0; progress.value = withTiming(1, {duration: 360, easing: Easing.bezier(0.32, 0.72, 0, 1)}); }, [progress]);
  const close = useCallback(() => { progress.value = withTiming(0, {duration: 280, easing: Easing.bezier(0.32, 0, 0, 1)}, () => runOnJS(setActive)(null)); }, [progress]);
  const style = useAnimatedStyle(() => { if (!active) return {opacity: 0}; const s = active.source, t = active.target; const p = progress.value; return {opacity: 1, position: 'absolute', left: s.x + (t.x - s.x) * p, top: s.y + (t.y - s.y) * p, width: s.w + (t.w - s.w) * p, height: s.h + (t.h - s.h) * p}; });
  return (<C.Provider value={{open, close, progress, active}}>{children}{active && <Animated.View pointerEvents='none' style={[s.floating, style]}><Image source={active.uri} style={StyleSheet.absoluteFill} contentFit='cover' cachePolicy='memory-disk'/></Animated.View>}</C.Provider>);
}
const s = StyleSheet.create({floating: {zIndex: 9999}});

