import React, {useRef} from 'react';
import {Pressable, View, StyleSheet} from 'react-native';
import {Image} from 'expo-image';
import {router} from 'expo-router';
import {useSharedImage} from './SharedImage';
export function GridCell({id, uri, aspectRatio}: {id:string; uri:string; aspectRatio:number}) {
  const ref = useRef<View>(null);
  const {open, active} = useSharedImage();
  const onPress = () => { ref.current?.measureInWindow((x, y, w, h) => { open({id, uri, source:{x,y,w,h}, target:{x:0, y:60, w:SW, h: SW/aspectRatio}, aspectRatio}); router.push(`/photo/${id}`); }); };
  const hidden = active?.id === id;
  return (<Pressable ref={ref} onPress={onPress} style={s.cell}><Image source={uri} style={[StyleSheet.absoluteFill, {opacity: hidden ? 0 : 1}]} contentFit='cover' cachePolicy='memory-disk'/></Pressable>);
}
