import React, {useEffect} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Path, Skia, SweepGradient, vec, Group, Text, useFont, BlurMask} from '@shopify/react-native-skia';
import {useSharedValue, useDerivedValue, withTiming, Easing} from 'react-native-reanimated';

type Props = {value: number; max?: number; size?: number; stroke?: number; colors?: string[]; label?: string};

export function ActivityRing({value, max = 100, size = 240, stroke = 22, colors = ['#FF2D55', '#FF9500', '#FFCC00'], label}: Props) {
  const progress = useSharedValue(0);
  const font = useFont(require('./assets/Inter-Bold.ttf'), size * 0.22);
  useEffect(() => { progress.value = withTiming(value / max, {duration: 900, easing: Easing.bezier(0.25, 0.1, 0.25, 1)}); }, [value, max]);
  const radius = (size - stroke) / 2 - 12; const cx = size / 2; const cy = size / 2;
  const arcPath = useDerivedValue(() => { const p = Skia.Path.Make(); const sweep = Math.min(progress.value, 1) * 360; p.addArc({x: cx - radius, y: cy - radius, width: radius*2, height: radius*2}, -90, sweep); return p; });
  const overflowPath = useDerivedValue(() => { const p = Skia.Path.Make(); const extra = Math.max(0, progress.value - 1) * 360; if (extra > 0) p.addArc({x: cx - radius + stroke + 4, y: cy - radius + stroke + 4, width: (radius - stroke - 4)*2, height: (radius - stroke - 4)*2}, -90, extra); return p; });
  const counterText = useDerivedValue(() => `${Math.round(progress.value * 100)}%`);
  const labelY = cy + size * 0.12; const counterY = cy + size * 0.04;
  if (!font) return <View style={{width: size, height: size}}/>;
  return (<View style={{width: size, height: size}}><Canvas style={StyleSheet.absoluteFill}><Group><Path path={Skia.Path.Make().addCircle(cx, cy, radius)} style='stroke' strokeWidth={stroke} color='rgba(255,255,255,0.06)'/></Group><Group><Path path={arcPath} style='stroke' strokeWidth={stroke} strokeCap='round'><SweepGradient c={vec(cx, cy)} colors={colors}/><BlurMask blur={4} style='solid'/></Path></Group><Group><Path path={overflowPath} style='stroke' strokeWidth={stroke * 0.7} strokeCap='round' color={colors[0]}/></Group><Text x={cx - size * 0.14} y={counterY} text={counterText} font={font} color='#fff'/></Canvas></View>);
}

