import {StyleSheet, Text, View} from 'react-native';
import {Canvas, Circle, Rect} from '@shopify/react-native-skia';
import {Easing, useSharedValue, withRepeat, withTiming} from 'react-native-reanimated';
export function CustomTabBarWithMorphingActiveIndicator() {
  const phase = useSharedValue(0);
  useEffect(() => { phase.value = withRepeat(withTiming(1, {duration: 1200, easing: Easing.inOut(Easing.cubic)}), -1, true); }, [phase]);
  const marks = useMemo(() => Array.from({length: 5}, (_, i) => ({id: i, x: 24 + i * 34, h: 24 + i * 8, color: i % 2 ? '#38bdf8' : '#0f766e'})), []);
  return <View style={styles.wrap} accessibilityRole="image" accessibilityLabel="Custom tab bar with morphing active indicator and badge counts"><Canvas style={styles.canvas}><Rect x={0} y={0} width={220} height={120} color="#f8fafc" />{marks.map((m) => <Circle key={m.id} cx={m.x} cy={80 - m.h / 2} r={Math.max(6, m.h / 4)} color={m.color} />)}</Canvas><Text style={styles.label}>Custom tab bar with morphing active indicator and badge counts</Text></View>;
}
const styles = StyleSheet.create({wrap: {gap: 8, alignItems: 'center'}, canvas: {width: 220, height: 120}, label: {fontWeight: '700', textAlign: 'center'}});

// AnimatedListRow.tsx
import React, {useRef} from 'react';
import {StyleSheet, View} from 'react-native';
import Animated, {FadeInDown, FadeOutLeft, Layout, Easing, AccessibilityInfo} from 'react-native-reanimated';
import {useReducedMotion} from 'react-native-reanimated';

const PER_ROW = 40; const MAX_DELAY = 240; const DUR = 320;

type Props = {index: number; isInitialMount?: boolean; children: React.ReactNode};
export function AnimatedListRow({index, isInitialMount = true, children}: Props) {
  const reducedMotion = useReducedMotion();
  if (reducedMotion) return <View style={{marginVertical: 4}}>{children}</View>;
  const delay = isInitialMount ? Math.min(index * PER_ROW, MAX_DELAY) : 0;
  const entering = FadeInDown.duration(DUR).delay(delay).easing(Easing.bezier(0.32, 0.72, 0, 1)).springify().damping(18);
  const exiting = FadeOutLeft.duration(220);
  return (<Animated.View entering={entering} exiting={exiting} layout={Layout.springify().damping(18).stiffness(220)} style={s.row}>{children}</Animated.View>);
}
const s = StyleSheet.create({row:{marginVertical:4}});

// AnimatedList.tsx — manages the 'initial mount' window
import React, {useEffect, useRef, useState} from 'react';
import {View} from 'react-native';
export function AnimatedList<T extends {id: string}>({data, renderItem}: {data: T[]; renderItem: (item: T, index: number) => React.ReactNode}) {
  const initialIdsRef = useRef<Set<string>>(new Set(data.map(d => d.id)));
  const initialMountWindowEndedRef = useRef(false);
  useEffect(() => { const t = setTimeout(() => { initialMountWindowEndedRef.current = true; }, MAX_DELAY + DUR); return () => clearTimeout(t); }, []);
  return (<View>{data.map((item, index) => { const wasInitial = initialIdsRef.current.has(item.id); return (<AnimatedListRow key={item.id} index={index} isInitialMount={wasInitial && !initialMountWindowEndedRef.current}>{renderItem(item, index)}</AnimatedListRow>); })}</View>);
}

