// Waveform.tsx
import React, {useEffect, useMemo} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Path, Skia, Group, Rect} from '@shopify/react-native-skia';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import {useSharedValue, useDerivedValue, runOnJS, useFrameCallback, withTiming} from 'react-native-reanimated';

type Props = {peaks: number[]; width: number; durationMs: number; positionMs: number; isPlaying: boolean; onSeek: (ms: number) => void; onScrubStart?: () => void; onScrubEnd?: () => void};
const BAR_W = 2; const BAR_GAP = 1; const H = 60;

export function Waveform({peaks, width, durationMs, positionMs, isPlaying, onSeek, onScrubStart, onScrubEnd}: Props) {
  const barCount = Math.floor(width / (BAR_W + BAR_GAP));
  const downsampled = useMemo(() => { const chunk = peaks.length / barCount; const out: number[] = []; for (let i = 0; i < barCount; i++) { const start = Math.floor(i * chunk); const end = Math.floor((i + 1) * chunk); let sum = 0; for (let j = start; j < end; j++) sum += peaks[j] ?? 0; out.push(sum / Math.max(1, end - start)); } return out; }, [peaks, barCount]);

  const progress = useSharedValue(positionMs / Math.max(1, durationMs));
  useEffect(() => { progress.value = withTiming(positionMs / Math.max(1, durationMs), {duration: 100}); }, [positionMs, durationMs]);
  const playheadX = useDerivedValue(() => progress.value * width);
  const pulse = useSharedValue(0.85);
  useFrameCallback(({timeSinceFirstFrame}) => { if (isPlaying) pulse.value = 0.7 + Math.sin(timeSinceFirstFrame / 200) * 0.15; });

  const playedPath = useDerivedValue(() => { const p = Skia.Path.Make(); const playedBars = Math.floor(progress.value * barCount); for (let i = 0; i < playedBars; i++) { const x = i * (BAR_W + BAR_GAP); const amp = downsampled[i] ?? 0; const h = Math.max(2, amp * H); p.addRect({x, y: (H - h) / 2, width: BAR_W, height: h}); } return p; });
  const unplayedPath = useMemo(() => { const p = Skia.Path.Make(); for (let i = 0; i < barCount; i++) { const x = i * (BAR_W + BAR_GAP); const amp = downsampled[i] ?? 0; const h = Math.max(2, amp * H); p.addRect({x, y: (H - h) / 2, width: BAR_W, height: h}); } return p; }, [downsampled, barCount]);

  const tap = Gesture.Tap().onEnd(e => { const ratio = Math.max(0, Math.min(1, e.x / width)); runOnJS(onSeek)(ratio * durationMs); });
  const pan = Gesture.Pan().onStart(() => { if (onScrubStart) runOnJS(onScrubStart)(); }).onUpdate(e => { const ratio = Math.max(0, Math.min(1, e.x / width)); progress.value = ratio; runOnJS(onSeek)(ratio * durationMs); }).onEnd(() => { if (onScrubEnd) runOnJS(onScrubEnd)(); });
  const gesture = Gesture.Race(pan, tap);

  return (<GestureDetector gesture={gesture}><View style={{width, height: H}}><Canvas style={StyleSheet.absoluteFill}><Path path={unplayedPath} color='#3A3A3C'/><Path path={playedPath} color='#FF453A'/><Rect x={playheadX} y={0} width={2} height={H} color='#FF453A' opacity={pulse}/></Canvas></View></GestureDetector>);
}

