  const stickyStyle = useAnimatedStyle(() => ({opacity: interpolate(scrollY.value, [STICKY_TRIGGER, STICKY_TRIGGER + 30], [0, 1], Extrapolation.CLAMP), transform: [{translateY: interpolate(scrollY.value, [STICKY_TRIGGER, STICKY_TRIGGER + 30], [8, 0], Extrapolation.CLAMP)}]}));

