// useUnsavedChangesGuard.tsx
import {useEffect, useCallback, useRef} from 'react';
import {Platform, BackHandler, ActionSheetIOS} from 'react-native';
import {useNavigation} from 'expo-router';
import {Gesture} from 'react-native-gesture-handler';
import {runOnJS} from 'react-native-reanimated';

type Options = {dirty: boolean; onConfirmDiscard: () => void; showAndroidDialog: () => Promise<boolean>};
export function useUnsavedChangesGuard({dirty, onConfirmDiscard, showAndroidDialog}: Options) {
  const navigation = useNavigation();
  const proceed = useCallback(() => { onConfirmDiscard(); navigation.goBack(); }, [onConfirmDiscard, navigation]);

  const promptIOS = useCallback(() => { ActionSheetIOS.showActionSheetWithOptions({title: 'Discard changes?', message: 'You have unsaved changes. Going back will lose them.', options: ['Discard', 'Keep editing'], destructiveButtonIndex: 0, cancelButtonIndex: 1, userInterfaceStyle: 'dark'}, idx => { if (idx === 0) proceed(); }); }, [proceed]);

  useEffect(() => { if (Platform.OS !== 'android') return; const sub = BackHandler.addEventListener('hardwareBackPress', () => { if (!dirty) return false; showAndroidDialog().then(confirmed => { if (confirmed) proceed(); }); return true; }); return () => sub.remove(); }, [dirty, proceed, showAndroidDialog]);

  useEffect(() => { navigation.setOptions({gestureEnabled: !dirty || Platform.OS !== 'ios'}); }, [dirty, navigation]);

  const edgePanGesture = Gesture.Pan().activeOffsetX([15, 9999]).enabled(Platform.OS === 'ios' && dirty).hitSlop({left: 0, width: 24}).onEnd(e => { if (e.translationX > 60 && Math.abs(e.velocityX) > 200) { runOnJS(promptIOS)(); }});

  return {edgePanGesture, promptIOS};
}

