import React, {useEffect} from 'react';
import {StyleSheet, View, Pressable, Platform, Dimensions} from 'react-native';
import {BlurView} from 'expo-blur';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, withTiming, runOnJS} from 'react-native-reanimated';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import {useSafeAreaInsets} from 'react-native-safe-area-context';

const {height: SH} = Dimensions.get('window');
const RADIUS = 24;

type Props = {visible: boolean; onDismiss: () => void; children: React.ReactNode};
export function GlassPanel({visible, onDismiss, children}: Props) {
  const insets = useSafeAreaInsets();
  const scale = useSharedValue(0.92);
  const opacity = useSharedValue(0);
  const dragY = useSharedValue(0);

  useEffect(() => { if (visible) { opacity.value = withTiming(1, {duration: 240}); scale.value = withSpring(1, {damping: 18, stiffness: 240}); dragY.value = 0; } else { opacity.value = withTiming(0, {duration: 160}); scale.value = withTiming(0.92, {duration: 160}); }}, [visible]);

  const scrimStyle = useAnimatedStyle(() => ({opacity: opacity.value * 0.4}));
  const panelStyle = useAnimatedStyle(() => ({opacity: opacity.value, transform: [{scale: scale.value}, {translateY: dragY.value}]}));

  const pan = Gesture.Pan().onUpdate(e => { dragY.value = Math.max(0, e.translationY); }).onEnd(e => { if (dragY.value > 80 || e.velocityY > 800) { dragY.value = withTiming(SH * 0.5, {duration: 180}, () => runOnJS(onDismiss)()); opacity.value = withTiming(0, {duration: 180}); } else { dragY.value = withSpring(0, {damping: 18, stiffness: 240}); }});

  if (!visible) return null;
  return (<View style={s.root}><Pressable onPress={onDismiss} style={StyleSheet.absoluteFill}><Animated.View style={[StyleSheet.absoluteFill, {backgroundColor: '#000'}, scrimStyle]}/></Pressable><GestureDetector gesture={pan}><Animated.View style={[s.panel, panelStyle, {top: insets.top + 60}]}>{Platform.OS === 'ios' ? (<BlurView intensity={70} tint='dark' style={s.backdrop}><View style={s.strokeOverlay} pointerEvents='none'/><View style={s.content}>{children}</View></BlurView>) : (<View style={[s.backdrop, s.androidBackdrop]}><View style={s.strokeOverlay} pointerEvents='none'/><View style={s.content}>{children}</View></View>)}</Animated.View></GestureDetector></View>);
}
const s = StyleSheet.create({root:{...StyleSheet.absoluteFillObject, justifyContent:'flex-start', alignItems:'center'}, panel:{width:'92%', maxWidth:480, borderRadius:RADIUS, overflow:'hidden'}, backdrop:{borderRadius:RADIUS, overflow:'hidden'}, androidBackdrop:{backgroundColor:'rgba(28, 28, 32, 0.92)', ...Platform.select({android:{elevation:24}})}, strokeOverlay:{...StyleSheet.absoluteFillObject, borderRadius:RADIUS, borderWidth:1.5, borderColor:Platform.OS === 'ios' ? 'rgba(255,255,255,0.18)' : 'rgba(255,255,255,0.08)'}, content:{padding:20, gap:12}});

