// Sectionizer.ts
export type SectionedItem<T> = {type: 'header'; letter: string; count: number} | {type: 'item'; data: T};
export function sectionize<T>(items: T[], keyFn: (item: T) => string): {flat: SectionedItem<T>[]; indices: number[]; letters: string[]} { const sorted = [...items].sort((a, b) => keyFn(a).localeCompare(keyFn(b))); const grouped = new Map<string, T[]>(); for (const it of sorted) { const letter = (keyFn(it)[0] ?? '#').toUpperCase(); const arr = grouped.get(letter) ?? []; arr.push(it); grouped.set(letter, arr); } const flat: SectionedItem<T>[] = []; const indices: number[] = []; const letters: string[] = []; for (const [letter, arr] of grouped) { indices.push(flat.length); letters.push(letter); flat.push({type: 'header', letter, count: arr.length}); for (const item of arr) flat.push({type: 'item', data: item}); } return {flat, indices, letters}; }

