import React, {useMemo, useRef} from 'react';
import {StyleSheet, View, Text, Pressable} from 'react-native';
import {FlashList} from '@shopify/flash-list';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import {runOnJS, useSharedValue} from 'react-native-reanimated';
import {sectionize, SectionedItem} from './Sectionizer';
import * as Haptics from 'expo-haptics';

type Contact = {id: string; name: string};
export function ContactsList({contacts, onPressContact}: {contacts: Contact[]; onPressContact: (c: Contact) => void}) {
  const {flat, indices, letters} = useMemo(() => sectionize(contacts, c => c.name), [contacts]);
  const listRef = useRef<FlashList<SectionedItem<Contact>>>(null);
  const renderItem = ({item}: {item: SectionedItem<Contact>}) => { if (item.type === 'header') return (<View style={s.header}><Text style={s.headerLetter}>{item.letter}</Text><Text style={s.headerCount}>{item.count}</Text></View>); return (<Pressable onPress={() => onPressContact(item.data)} style={s.row}><View style={s.avatar}><Text style={s.avatarText}>{item.data.name[0]}</Text></View><Text style={s.name}>{item.data.name}</Text></Pressable>); };
  const stickyIndices = useMemo(() => indices, [indices]);
  const getItemType = (item: SectionedItem<Contact>) => item.type;
  return (<View style={s.root}><FlashList ref={listRef} data={flat} renderItem={renderItem} keyExtractor={(item, i) => item.type === 'header' ? `h-${item.letter}` : `i-${item.data.id}`} estimatedItemSize={52} stickyHeaderIndices={stickyIndices} getItemType={getItemType}/><IndexScrubber letters={letters} indices={indices} onPick={i => listRef.current?.scrollToIndex({index: i, animated: false})}/></View>);
}

function IndexScrubber({letters, indices, onPick}: {letters: string[]; indices: number[]; onPick: (i: number) => void}) {
  const trackHeight = useSharedValue(0);
  const lastLetter = useSharedValue('');
  const pickLetter = (i: number) => { Haptics.selectionAsync(); onPick(indices[i]); };
  const pan = Gesture.Pan().minDistance(0).onUpdate(e => { const idx = Math.max(0, Math.min(letters.length - 1, Math.floor((e.y / trackHeight.value) * letters.length))); const letter = letters[idx]; if (letter !== lastLetter.value) { lastLetter.value = letter; runOnJS(pickLetter)(idx); }});
  return (<View style={s.scrubber} onLayout={e => { trackHeight.value = e.nativeEvent.layout.height; }}><GestureDetector gesture={pan}><View style={s.scrubberInner}>{letters.map(l => (<Text key={l} style={s.scrubberLetter}>{l}</Text>))}</View></GestureDetector></View>);
}
const s = StyleSheet.create({root:{flex:1, flexDirection:'row', backgroundColor:'#000'}, header:{height:36, flexDirection:'row', alignItems:'center', justifyContent:'space-between', paddingHorizontal:16, backgroundColor:'#0A0A0A'}, headerLetter:{color:'#0A84FF', fontSize:14, fontWeight:'700'}, headerCount:{color:'#8E8E93', fontSize:12}, row:{height:52, flexDirection:'row', alignItems:'center', paddingHorizontal:16, gap:12, backgroundColor:'#000'}, avatar:{width:36, height:36, borderRadius:18, backgroundColor:'#1C1C1E', alignItems:'center', justifyContent:'center'}, avatarText:{color:'#fff', fontWeight:'600'}, name:{color:'#fff', fontSize:16}, scrubber:{position:'absolute', right:4, top:0, bottom:0, justifyContent:'center'}, scrubberInner:{paddingHorizontal:6, paddingVertical:8, gap:1, backgroundColor:'rgba(28,28,32,0.6)', borderRadius:10}, scrubberLetter:{color:'#0A84FF', fontSize:10, fontWeight:'700', textAlign:'center'}});

// PhotoViewer.tsx
import React from 'react';
import {StyleSheet, View, useWindowDimensions} from 'react-native';
import {Image} from 'expo-image';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, runOnJS, useDerivedValue} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';

const MIN_S = 1; const MAX_S = 5; const DOUBLE_S = 2;
const SPRING = {damping: 18, stiffness: 220};

type Props = {uri: string; aspectRatio: number; onSingleTap?: () => void};
export function PhotoViewer({uri, aspectRatio, onSingleTap}: Props) {
  const {width: SW, height: SH} = useWindowDimensions();
  const imgW = SW; const imgH = SW / aspectRatio;
  const scale = useSharedValue(1); const savedScale = useSharedValue(1);
  const tx = useSharedValue(0); const ty = useSharedValue(0); const savedTx = useSharedValue(0); const savedTy = useSharedValue(0);
  const focalX = useSharedValue(0); const focalY = useSharedValue(0);

  const clampBounds = (s: number) => { 'worklet'; const maxTx = Math.max(0, (imgW * s - SW) / 2); const maxTy = Math.max(0, (imgH * s - SH) / 2); return {maxTx, maxTy}; };
  const settle = () => { 'worklet'; let nextS = scale.value; if (nextS < MIN_S) nextS = MIN_S; else if (nextS > MAX_S) nextS = MAX_S; const {maxTx, maxTy} = clampBounds(nextS); let nextTx = tx.value; let nextTy = ty.value; if (nextTx > maxTx) nextTx = maxTx; if (nextTx < -maxTx) nextTx = -maxTx; if (nextTy > maxTy) nextTy = maxTy; if (nextTy < -maxTy) nextTy = -maxTy; scale.value = withSpring(nextS, SPRING); tx.value = withSpring(nextTx, SPRING); ty.value = withSpring(nextTy, SPRING); };

  const pinch = Gesture.Pinch().onStart(e => { savedScale.value = scale.value; focalX.value = e.focalX - SW / 2; focalY.value = e.focalY - SH / 2; }).onUpdate(e => { scale.value = savedScale.value * e.scale; }).onEnd(() => { settle(); });
  const pan = Gesture.Pan().onStart(() => { savedTx.value = tx.value; savedTy.value = ty.value; }).onUpdate(e => { if (scale.value <= 1.05) return; const {maxTx, maxTy} = clampBounds(scale.value); let nextTx = savedTx.value + e.translationX; let nextTy = savedTy.value + e.translationY; if (nextTx > maxTx) nextTx = maxTx + (nextTx - maxTx) * 0.4; if (nextTx < -maxTx) nextTx = -maxTx + (nextTx + maxTx) * 0.4; if (nextTy > maxTy) nextTy = maxTy + (nextTy - maxTy) * 0.4; if (nextTy < -maxTy) nextTy = -maxTy + (nextTy + maxTy) * 0.4; tx.value = nextTx; ty.value = nextTy; }).onEnd(() => { settle(); });
  const doubleTap = Gesture.Tap().numberOfTaps(2).onEnd(e => { runOnJS(Haptics.selectionAsync)(); if (scale.value > 1.1) { scale.value = withSpring(1, SPRING); tx.value = withSpring(0, SPRING); ty.value = withSpring(0, SPRING); } else { const fx = e.x - SW / 2; const fy = e.y - SH / 2; scale.value = withSpring(DOUBLE_S, SPRING); tx.value = withSpring(-fx * (DOUBLE_S - 1), SPRING); ty.value = withSpring(-fy * (DOUBLE_S - 1), SPRING); }});
  const singleTap = Gesture.Tap().numberOfTaps(1).maxDelay(250).requireExternalGestureToFail(doubleTap).onEnd(() => { if (onSingleTap) runOnJS(onSingleTap)(); });
  const gesture = Gesture.Simultaneous(pinch, pan, Gesture.Race(doubleTap, singleTap));

  const style = useAnimatedStyle(() => ({transform: [{translateX: tx.value}, {translateY: ty.value}, {scale: scale.value}]}));
  return (<GestureDetector gesture={gesture}><View style={s.root}><Animated.View style={[{width: imgW, height: imgH, alignSelf: 'center', marginTop: (SH - imgH) / 2}, style]}><Image source={uri} style={StyleSheet.absoluteFill} contentFit='contain' cachePolicy='memory-disk'/></Animated.View></View></GestureDetector>);
}
const s = StyleSheet.create({root:{flex:1, backgroundColor:'#000'}});

// LiveTrackMap.tsx
import React, {useEffect, useRef, useState, useCallback} from 'react';
import {StyleSheet, View, Pressable, Text} from 'react-native';
import MapView, {Polyline, Marker, Region} from 'react-native-maps';
import * as Location from 'expo-location';
import Animated, {useSharedValue, useAnimatedStyle, withRepeat, withTiming, Easing} from 'react-native-reanimated';
import {useSafeAreaInsets} from 'react-native-safe-area-context';
import * as Haptics from 'expo-haptics';

type Coord = {latitude: number; longitude: number};
export function LiveTrackMap() {
  const insets = useSafeAreaInsets();
  const mapRef = useRef<MapView>(null);
  const [path, setPath] = useState<Coord[]>([]);
  const [user, setUser] = useState<Coord | null>(null);
  const [autoFollow, setAutoFollow] = useState(true);
  const pulse = useSharedValue(1);

  useEffect(() => { pulse.value = withRepeat(withTiming(1.25, {duration: 900, easing: Easing.inOut(Easing.sin)}), -1, true); }, []);

  useEffect(() => { let sub: Location.LocationSubscription | null = null; (async () => { const {status} = await Location.requestForegroundPermissionsAsync(); if (status !== 'granted') return; sub = await Location.watchPositionAsync({accuracy: Location.Accuracy.BestForNavigation, distanceInterval: 5, timeInterval: 2000}, loc => { const c = {latitude: loc.coords.latitude, longitude: loc.coords.longitude}; setUser(c); setPath(prev => [...prev, c]); if (autoFollow) mapRef.current?.animateToRegion({...c, latitudeDelta: 0.005, longitudeDelta: 0.005}, 800); }); })(); return () => { sub?.remove(); }; }, [autoFollow]);

  const onPanDrag = useCallback(() => { if (autoFollow) setAutoFollow(false); }, [autoFollow]);
  const recenter = useCallback(() => { Haptics.selectionAsync(); setAutoFollow(true); if (user) mapRef.current?.animateToRegion({...user, latitudeDelta: 0.005, longitudeDelta: 0.005}, 600); }, [user]);

  const pulseStyle = useAnimatedStyle(() => ({transform: [{scale: pulse.value}]}));

  return (<View style={s.root}><MapView ref={mapRef} style={StyleSheet.absoluteFill} onPanDrag={onPanDrag} showsUserLocation={false}>{path.length > 1 && (<Polyline coordinates={path} strokeWidth={5} strokeColor='#0A84FF' lineCap='round' lineJoin='round'/>)}{user && (<Marker coordinate={user} anchor={{x: 0.5, y: 0.5}}><View style={s.userMarkerWrap}><Animated.View style={[s.userPulse, pulseStyle]}/><View style={s.userMarker}/></View></Marker>)}</MapView>{!autoFollow && (<Pressable onPress={recenter} style={[s.fab, {bottom: insets.bottom + 24}]} accessibilityRole='button' accessibilityLabel='Recenter on my location'><Text style={s.fabIcon}>{'◎'}</Text></Pressable>)}</View>);
}
const s = StyleSheet.create({root:{flex:1, backgroundColor:'#000'}, userMarkerWrap:{width:40, height:40, alignItems:'center', justifyContent:'center'}, userMarker:{width:14, height:14, borderRadius:7, backgroundColor:'#0A84FF', borderWidth:3, borderColor:'#fff'}, userPulse:{position:'absolute', width:30, height:30, borderRadius:15, backgroundColor:'rgba(10,132,255,0.3)'}, fab:{position:'absolute', right:16, width:48, height:48, borderRadius:24, backgroundColor:'#1C1C1E', alignItems:'center', justifyContent:'center', borderWidth:1, borderColor:'rgba(255,255,255,0.1)'}, fabIcon:{color:'#0A84FF', fontSize:20}});

// PullToRefresh.tsx
import React, {useState, useCallback} from 'react';
import {StyleSheet, View, Text, Platform} from 'react-native';
import Animated, {useSharedValue, useAnimatedScrollHandler, useAnimatedStyle, useDerivedValue, interpolate, Extrapolation, withTiming, withRepeat, Easing, runOnJS} from 'react-native-reanimated';
import {Canvas, Path, Skia} from '@shopify/react-native-skia';
import * as Haptics from 'expo-haptics';

const THRESHOLD = 80; const SIZE = 32;
type State = 'idle'|'pulling'|'ready'|'refreshing'|'done';
type Props = {onRefresh: () => Promise<void>; children: React.ReactElement<any>};

export function PullToRefresh({onRefresh, children}: Props) {
  const [state, setState] = useState<State>('idle');
  const scrollY = useSharedValue(0); const rotate = useSharedValue(0); const indicatorOpacity = useSharedValue(0);
  const handler = useAnimatedScrollHandler({onScroll: e => { scrollY.value = e.contentOffset.y; }, onEndDrag: e => { if (e.contentOffset.y <= -THRESHOLD && state === 'pulling') { runOnJS(triggerRefresh)(); }}});
  const triggerRefresh = useCallback(async () => { setState('refreshing'); Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium); indicatorOpacity.value = withTiming(1); rotate.value = withRepeat(withTiming(360, {duration: 900, easing: Easing.linear}), -1, false); try { await Promise.race([onRefresh(), new Promise((_, rj) => setTimeout(() => rj(new Error('timeout')), 12000))]); setState('done'); rotate.value = withTiming(0, {duration: 0}); Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success); setTimeout(() => { indicatorOpacity.value = withTiming(0, {duration: 280}); setState('idle'); }, 500); } catch { setState('idle'); rotate.value = withTiming(0); indicatorOpacity.value = withTiming(0); Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error); }}, [onRefresh]);
  React.useEffect(() => { if (state === 'idle' || state === 'refreshing' || state === 'done') return; }, [state]);
  React.useEffect(() => { const id = setInterval(() => { if (state === 'idle') { const pulled = -scrollY.value > 10; if (pulled) setState('pulling'); }}, 100); return () => clearInterval(id); }, [state]);

  const pullProgress = useDerivedValue(() => interpolate(-scrollY.value, [0, THRESHOLD], [0, 1], Extrapolation.CLAMP));
  const indStyle = useAnimatedStyle(() => ({opacity: state === 'refreshing' || state === 'done' ? indicatorOpacity.value : pullProgress.value, transform: [{scale: 0.7 + pullProgress.value * 0.3}, {rotate: `${rotate.value}deg`}]}));
  const arcPath = useDerivedValue(() => { const p = Skia.Path.Make(); const angle = (state === 'refreshing' ? 270 : pullProgress.value * 360); p.addArc({x: 2, y: 2, width: SIZE - 4, height: SIZE - 4}, -90, angle); return p; });

  return (<View style={s.root}><Animated.View pointerEvents='none' style={[s.indicator, indStyle]}><Canvas style={{width: SIZE, height: SIZE}}><Path path={arcPath} style='stroke' strokeWidth={3} color='#0A84FF' strokeCap='round'/></Canvas></Animated.View>{React.cloneElement(children, {onScroll: handler, scrollEventThrottle: 16, bounces: true, overScrollMode: 'always'})}</View>);
}
const s = StyleSheet.create({root:{flex:1}, indicator:{position:'absolute', top:60, alignSelf:'center', width:SIZE, height:SIZE, zIndex:10}});

// WheelStyleDatePickerWithMomentumScroll.tsx
import React, {useEffect, useMemo} from 'react';
import {StyleSheet, Text, View} from 'react-native';
import {Canvas, Circle, Rect} from '@shopify/react-native-skia';
import {Easing, useSharedValue, withRepeat, withTiming} from 'react-native-reanimated';
export function WheelStyleDatePickerWithMomentumScroll() {
  const phase = useSharedValue(0);
  useEffect(() => { phase.value = withRepeat(withTiming(1, {duration: 1200, easing: Easing.inOut(Easing.cubic)}), -1, true); }, [phase]);
  const marks = useMemo(() => Array.from({length: 5}, (_, i) => ({id: i, x: 24 + i * 34, h: 24 + i * 8, color: i % 2 ? '#38bdf8' : '#0f766e'})), []);
  return <View style={styles.wrap} accessibilityRole="image" accessibilityLabel="Wheel-style date picker with momentum scroll and haptic per row"><Canvas style={styles.canvas}><Rect x={0} y={0} width={220} height={120} color="#f8fafc" />{marks.map((m) => <Circle key={m.id} cx={m.x} cy={80 - m.h / 2} r={Math.max(6, m.h / 4)} color={m.color} />)}</Canvas><Text style={styles.label}>Wheel-style date picker with momentum scroll and haptic per row</Text></View>;
}
const styles = StyleSheet.create({wrap: {gap: 8, alignItems: 'center'}, canvas: {width: 220, height: 120}, label: {fontWeight: '700', textAlign: 'center'}});

// Sparkline.tsx
import React, {useEffect, useMemo} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Path, Skia} from '@shopify/react-native-skia';
import {useSharedValue, withTiming, useDerivedValue, Easing} from 'react-native-reanimated';

type Props = {points: number[]; width?: number; height?: number; animate?: boolean; up?: boolean};
export function Sparkline({points, width = 80, height = 32, animate = false, up = true}: Props) {
  const path = useMemo(() => { const p = Skia.Path.Make(); if (points.length < 2) return p; const min = Math.min(...points); const max = Math.max(...points); const range = max - min || 1; points.forEach((v, i) => { const x = (i / (points.length - 1)) * width; const y = height - ((v - min) / range) * height; if (i === 0) p.moveTo(x, y); else p.lineTo(x, y); }); return p; }, [points, width, height]);
  const progress = useSharedValue(animate ? 0 : 1);
  useEffect(() => { if (animate) progress.value = withTiming(1, {duration: 400, easing: Easing.bezier(0.32, 0, 0.32, 1)}); }, []);
  const trimmedPath = useDerivedValue(() => { if (progress.value >= 1) return path; const copy = path.copy(); copy.trim(0, progress.value, false); return copy; });
  return (<View style={{width, height}}><Canvas style={StyleSheet.absoluteFill}><Path path={trimmedPath} style='stroke' strokeWidth={1.6} strokeCap='round' strokeJoin='round' color={up ? '#30D158' : '#FF453A'}/></Canvas></View>);
}

// Watchlist.tsx
import React, {useCallback, useRef} from 'react';
import {StyleSheet, View, Text} from 'react-native';
import {FlashList, ViewToken} from '@shopify/flash-list';
import {Sparkline} from './Sparkline';

type Item = {id: string; symbol: string; name: string; price: number; change: number; points: number[]};
export function Watchlist({items}: {items: Item[]}) {
  const animatedRef = useRef<Set<string>>(new Set());
  const onViewable = useCallback(({viewableItems}: {viewableItems: ViewToken[]}) => { viewableItems.forEach(v => { if (v.item) animatedRef.current.add(v.item.id); }); }, []);
  return (<FlashList data={items} estimatedItemSize={64} keyExtractor={i => i.id} onViewableItemsChanged={onViewable} viewabilityConfig={{itemVisiblePercentThreshold: 20}} renderItem={({item}) => (<Row item={item} firstSeen={!animatedRef.current.has(item.id)}/>)}/>);
}
const Row = React.memo(function Row({item, firstSeen}: {item: Item; firstSeen: boolean}) { const up = item.change >= 0; return (<View style={s.row}><View style={s.left}><Text style={s.symbol}>{item.symbol}</Text><Text style={s.name} numberOfLines={1}>{item.name}</Text></View><Sparkline points={item.points} animate={firstSeen} up={up}/><View style={s.right}><Text style={s.price}>{item.price.toFixed(2)}</Text><Text style={[s.change, up ? s.up : s.down]}>{up ? '+' : ''}{item.change.toFixed(2)}%</Text></View></View>); });
const s = StyleSheet.create({row:{height:64, flexDirection:'row', alignItems:'center', paddingHorizontal:16, gap:12}, left:{flex:1}, symbol:{color:'#fff', fontSize:16, fontWeight:'600'}, name:{color:'#8E8E93', fontSize:12, marginTop:2}, right:{minWidth:80, alignItems:'flex-end'}, price:{color:'#fff', fontSize:15, fontVariant:['tabular-nums']}, change:{fontSize:12, fontVariant:['tabular-nums'], marginTop:2}, up:{color:'#30D158'}, down:{color:'#FF453A'}});

// Slider.tsx
import React, {useCallback, useState} from 'react';
import {StyleSheet, View, Text, Platform, AccessibilityActionEvent} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, withTiming, runOnJS, useDerivedValue} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';

type Props = {value: number; min?: number; max?: number; step?: number; onChange: (v: number) => void; label: string; format?: (v: number) => string};
const THUMB = 28; const THUMB_ACTIVE = 36; const TRACK_H = 6;

export function Slider({value, min = 0, max = 100, step = 1, onChange, label, format = v => `${Math.round(v)}`}: Props) {
  const [width, setWidth] = useState(0);
  const progress = useSharedValue((value - min) / (max - min));
  const thumbScale = useSharedValue(1); const pillOpacity = useSharedValue(0);
  React.useEffect(() => { progress.value = withSpring((value - min) / (max - min), {damping: 22, stiffness: 280}); }, [value, min, max]);
  const updateValue = (ratio: number, fireHaptic: boolean) => { const raw = min + ratio * (max - min); const snapped = Math.round(raw / step) * step; const clamped = Math.max(min, Math.min(max, snapped)); if (clamped !== value) { if (fireHaptic) Haptics.selectionAsync(); onChange(clamped); }};
  const pan = Gesture.Pan().activeOffsetX([-3, 3]).failOffsetY([-10, 10]).onStart(e => { thumbScale.value = withSpring(Platform.OS === 'ios' ? 1.25 : 1, {damping: 14, stiffness: 280}); pillOpacity.value = withTiming(1, {duration: 120}); }).onUpdate(e => { const ratio = Math.max(0, Math.min(1, e.x / width)); progress.value = ratio; runOnJS(updateValue)(ratio, true); }).onEnd(() => { thumbScale.value = withSpring(1, {damping: 14, stiffness: 280}); pillOpacity.value = withTiming(0, {duration: 200}); });
  const onAccessibilityAction = useCallback((e: AccessibilityActionEvent) => { if (e.nativeEvent.actionName === 'increment') onChange(Math.min(max, value + step)); else if (e.nativeEvent.actionName === 'decrement') onChange(Math.max(min, value - step)); Haptics.selectionAsync(); }, [value, min, max, step, onChange]);

  const fillStyle = useAnimatedStyle(() => ({width: `${progress.value * 100}%`}));
  const thumbStyle = useAnimatedStyle(() => ({left: progress.value * width - THUMB / 2, transform: [{scale: thumbScale.value}]}));
  const pillStyle = useAnimatedStyle(() => ({opacity: pillOpacity.value, transform: [{translateY: pillOpacity.value * -8 - 40}, {translateX: progress.value * width - 24}]}));
  const valueText = format(value);

  return (<View accessibilityRole='adjustable' accessibilityLabel={label} accessibilityValue={{min, max, now: value, text: `${valueText}`}} onAccessibilityAction={onAccessibilityAction} accessibilityActions={[{name: 'increment'}, {name: 'decrement'}]} style={s.root} hitSlop={{top: 16, bottom: 16, left: 8, right: 8}}><GestureDetector gesture={pan}><View style={s.touchArea} onLayout={e => setWidth(e.nativeEvent.layout.width)}><Animated.View style={[s.pill, pillStyle]}><Text style={s.pillText}>{valueText}</Text></Animated.View><View style={s.track}><Animated.View style={[s.fill, fillStyle]}/></View><Animated.View style={[s.thumb, thumbStyle]}/></View></GestureDetector></View>);
}
const s = StyleSheet.create({root:{paddingVertical:16}, touchArea:{height:44, justifyContent:'center'}, track:{height:TRACK_H, backgroundColor:'#2C2C2E', borderRadius:TRACK_H/2}, fill:{height:'100%', backgroundColor:'#0A84FF', borderRadius:TRACK_H/2}, thumb:{position:'absolute', width:THUMB, height:THUMB, borderRadius:THUMB/2, backgroundColor:'#fff', ...Platform.select({ios:{shadowColor:'#000', shadowOpacity:0.2, shadowRadius:6, shadowOffset:{width:0,height:2}}, android:{elevation:4}})}, pill:{position:'absolute', width:48, height:32, borderRadius:8, backgroundColor:'#1C1C1E', alignItems:'center', justifyContent:'center', borderWidth:1, borderColor:'rgba(255,255,255,0.1)'}, pillText:{color:'#fff', fontSize:14, fontWeight:'600', fontVariant:['tabular-nums']}});
